fun solve(n: Long): Array<Long> {
    // Iterate over b, starting from 1.
    var b = 1L
    while (true) {
        val bCubed = b * b * b

        // Check if the smallest possible sum involving b (when a=1) exceeds n.
        // Since a >= 1, 1^3 + b^3 must be <= n.
        if (1L + bCubed > n) {
            break
        }

        // Iterate over a, such that 1 <= a <= b
        var a = 1L
        while (true) {
            if (a > b) break

            val aCubed = a * a * a
            val s = aCubed + bCubed

            if (s > n) {
                // Since a is increasing, subsequent sums will also exceed n.
                break
            }

            // Record the sum and increment its count
            sumCounts[s] = sumCounts.getOrDefault(s, 0) + 1

            a++
        }

        b++
    }

    // Collect all numbers that appeared at least twice
    val goodNumbers = sumCounts.keys
        .filter { sumCounts[it]!! >= 2 }
        .sorted()
        .toLongArray()

    return goodNumbers
}

